import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

export default function AdminUsers() {
  const [searchParams] = useSearchParams();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    role: searchParams.get('role') || '',
    status: searchParams.get('status') || '',
    page: 1,
  });
  const [total, setTotal] = useState(0);
  const [pages, setPages] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filters.role) params.set('role', filters.role);
      if (filters.status) params.set('status', filters.status);
      params.set('page', filters.page);
      params.set('limit', 15);
      const res = await api.get(`/users?${params}`);
      setUsers(res.data.data);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {
      toast.error('Failed to load users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, [filters]);

  const approveUser = async (id, name) => {
    try {
      await api.put(`/users/${id}/approve`);
      toast.success(`${name} approved`);
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const rejectUser = async (id, name) => {
    const reason = prompt(`Reason for rejecting ${name}:`);
    if (reason === null) return;
    try {
      await api.put(`/users/${id}/reject`, { reason });
      toast.success(`${name} rejected`);
      fetchUsers();
    } catch { toast.error('Failed'); }
  };

  const deleteUser = async (id, name) => {
    if (!window.confirm(`Delete user ${name}? This cannot be undone.`)) return;
    try {
      await api.delete(`/users/${id}`);
      toast.success('User deleted');
      fetchUsers();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const stats = {
    total: total,
    pending: users.filter(u => u.status === 'pending').length,
    approved: users.filter(u => u.status === 'approved').length,
    rejected: users.filter(u => u.status === 'rejected').length,
    admin: users.filter(u => u.role === 'admin').length,
    communityAdmin: users.filter(u => u.role === 'community_admin').length,
    student: users.filter(u => u.role === 'student').length,
  };

  const filteredUsers = users.filter(u =>
    u.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.itNumber?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* Enhanced Header */}
        <div style={{
          background: 'linear-gradient(135deg, rgba(15, 25, 35, 0.8) 0%, rgba(10, 18, 26, 0.9) 100%)',
          borderRadius: 'var(--border-radius-lg)',
          padding: '28px 32px',
          marginBottom: '32px',
          border: '1px solid rgba(0, 255, 255, 0.15)',
          position: 'relative',
          overflow: 'hidden',
        }}>
          <div style={{
            position: 'absolute',
            top: -30,
            right: -30,
            width: 150,
            height: 150,
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(0, 255, 255, 0.08) 0%, transparent 70%)',
            pointerEvents: 'none',
          }} />
          <div className="flex-between" style={{ position: 'relative', zIndex: 1 }}>
            <div>
              <h1 style={{
                fontFamily: 'var(--font-display)',
                fontSize: '1.8rem',
                marginBottom: '8px',
                letterSpacing: '-0.02em',
              }}>
                USER <span className="gradient-text">MANAGEMENT</span>
              </h1>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap' }}>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  background: 'rgba(0, 255, 255, 0.1)',
                  padding: '4px 12px',
                  borderRadius: '20px',
                  fontSize: '0.85rem',
                  color: 'var(--cyan-accent)',
                }}>
                  <span>👥</span>
                  <span>{total} Total Users</span>
                </div>
              </div>
            </div>
            <Link to="/admin" className="btn btn-outline" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              ← Dashboard
            </Link>
          </div>
        </div>

        {/* Stats Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(6, 1fr)',
          gap: '12px',
          marginBottom: '32px',
        }}>
          {[
            { label: 'Total', value: stats.total, icon: '👥', color: 'var(--cyan-accent)' },
            { label: 'Pending', value: stats.pending, icon: '⏳', color: 'var(--warning)' },
            { label: 'Approved', value: stats.approved, icon: '✓', color: 'var(--success)' },
            { label: 'Rejected', value: stats.rejected, icon: '✗', color: 'var(--error)' },
            { label: 'Admins', value: stats.admin, icon: '👑', color: 'var(--purple-light)' },
            { label: 'Students', value: stats.student, icon: '🎓', color: 'var(--cyan-accent)' },
          ].map((stat, i) => (
            <div key={i} style={{
              background: 'rgba(10, 18, 26, 0.6)',
              backdropFilter: 'blur(10px)',
              borderRadius: '12px',
              padding: '12px 12px',
              border: `1px solid ${stat.color}20`,
              transition: 'all 0.3s ease',
              textAlign: 'center',
            }}>
              <div style={{ fontSize: '1.2rem', marginBottom: '4px' }}>{stat.icon}</div>
              <div style={{ fontSize: '1.3rem', fontWeight: 700, color: stat.color }}>{stat.value}</div>
              <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }}>{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Filter Section */}
        <div style={{
          display: 'flex',
          flexWrap: 'wrap',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '16px',
          marginBottom: '28px',
        }}>
          {/* Filter Tabs */}
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            {/* Role Filters */}
            {[
              ['', 'All Roles', '👥'],
              ['admin', 'Admin', '👑'],
              ['community_admin', 'Community Admin', '🏛️'],
              ['student', 'Student', '🎓'],
            ].map(([v, l, icon]) => (
              <button
                key={v}
                onClick={() => setFilters(p => ({ ...p, role: v, page: 1 }))}
                style={{
                  padding: '8px 16px',
                  borderRadius: '40px',
                  border: `1px solid ${filters.role === v ? 'var(--cyan-accent)' : 'rgba(0, 255, 255, 0.2)'}`,
                  background: filters.role === v ? 'rgba(0, 255, 255, 0.1)' : 'transparent',
                  color: filters.role === v ? 'var(--cyan-accent)' : 'var(--text-secondary)',
                  cursor: 'pointer',
                  fontSize: '0.8rem',
                  fontWeight: 500,
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                }}
                onMouseEnter={(e) => {
                  if (filters.role !== v) {
                    e.currentTarget.style.borderColor = 'var(--cyan-accent)';
                    e.currentTarget.style.color = 'var(--cyan-accent)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (filters.role !== v) {
                    e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.2)';
                    e.currentTarget.style.color = 'var(--text-secondary)';
                  }
                }}
              >
                <span>{icon}</span> {l}
              </button>
            ))}

            <div style={{ width: '1px', background: 'rgba(0, 255, 255, 0.2)', margin: '0 4px' }} />

            {/* Status Filters */}
            {[
              ['', 'All Status', '📋'],
              ['pending', 'Pending', '⏳'],
              ['approved', 'Approved', '✓'],
              ['rejected', 'Rejected', '✗'],
            ].map(([v, l, icon]) => (
              <button
                key={v}
                onClick={() => setFilters(p => ({ ...p, status: v, page: 1 }))}
                style={{
                  padding: '8px 16px',
                  borderRadius: '40px',
                  border: `1px solid ${filters.status === v ? 'var(--cyan-accent)' : 'rgba(0, 255, 255, 0.2)'}`,
                  background: filters.status === v ? 'rgba(0, 255, 255, 0.1)' : 'transparent',
                  color: filters.status === v ? 'var(--cyan-accent)' : 'var(--text-secondary)',
                  cursor: 'pointer',
                  fontSize: '0.8rem',
                  fontWeight: 500,
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                }}
                onMouseEnter={(e) => {
                  if (filters.status !== v) {
                    e.currentTarget.style.borderColor = 'var(--cyan-accent)';
                    e.currentTarget.style.color = 'var(--cyan-accent)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (filters.status !== v) {
                    e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.2)';
                    e.currentTarget.style.color = 'var(--text-secondary)';
                  }
                }}
              >
                <span>{icon}</span> {l}
              </button>
            ))}
          </div>

          {/* Search Bar */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            background: 'rgba(10, 18, 26, 0.6)',
            borderRadius: '40px',
            padding: '6px 16px',
            border: '1px solid rgba(0, 255, 255, 0.2)',
          }}>
            <span style={{ marginRight: '8px', color: 'var(--text-muted)' }}>🔍</span>
            <input
              type="text"
              placeholder="Search by name, email, or IT number..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                background: 'transparent',
                border: 'none',
                color: 'var(--text-primary)',
                fontSize: '0.85rem',
                outline: 'none',
                minWidth: '240px',
              }}
            />
            {searchTerm && (
              <button
                onClick={() => setSearchTerm('')}
                style={{
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer',
                  marginLeft: '8px',
                }}
              >
                ✕
              </button>
            )}
          </div>
        </div>

        {/* Users Grid/Cards View */}
        {loading ? (
          <div className="loading-screen"><div className="spinner" /></div>
        ) : filteredUsers.length === 0 ? (
          <div className="empty-state" style={{
            padding: '60px 20px',
            textAlign: 'center',
            background: 'rgba(10, 18, 26, 0.4)',
            borderRadius: '24px',
            border: '1px solid rgba(0, 255, 255, 0.1)',
          }}>
            <div className="empty-state-icon" style={{ fontSize: '3rem', marginBottom: '16px' }}>👤</div>
            <div style={{ fontSize: '1rem', marginBottom: '8px' }}>No users found</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Try adjusting your filters or search term</div>
          </div>
        ) : (
          <>
            {/* Card Grid View */}
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))',
              gap: '20px',
              marginBottom: '32px',
            }}>
              {filteredUsers.map(u => (
                <div key={u._id} style={{
                  background: 'rgba(10, 18, 26, 0.5)',
                  borderRadius: '20px',
                  border: `1px solid ${
                    u.status === 'pending' ? 'rgba(255, 193, 7, 0.2)' : 
                    u.status === 'approved' ? 'rgba(0, 255, 0, 0.2)' : 
                    'rgba(255, 0, 0, 0.2)'
                  }`,
                  overflow: 'hidden',
                  transition: 'all 0.3s ease',
                  backdropFilter: 'blur(10px)',
                }} onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'translateY(-4px)';
                  e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.3)';
                }} onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.borderColor = u.status === 'pending' ? 'rgba(255, 193, 7, 0.2)' : u.status === 'approved' ? 'rgba(0, 255, 0, 0.2)' : 'rgba(255, 0, 0, 0.2)';
                }}>
                  {/* Status Bar */}
                  <div style={{
                    height: '4px',
                    background: u.status === 'pending' ? 'var(--warning)' : u.status === 'approved' ? 'var(--success)' : 'var(--error)',
                  }} />

                  <div style={{ padding: '20px' }}>
                    {/* User Header */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '14px', marginBottom: '16px' }}>
                      <div style={{
                        width: '60px',
                        height: '60px',
                        borderRadius: '50%',
                        background: `linear-gradient(135deg, ${u.role === 'admin' ? 'var(--purple-light)' : u.role === 'community_admin' ? 'var(--cyan-accent)' : 'var(--text-secondary)'}40, transparent)`,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '1.6rem',
                        fontWeight: 600,
                        color: u.role === 'admin' ? 'var(--purple-light)' : u.role === 'community_admin' ? 'var(--cyan-accent)' : 'var(--text-secondary)',
                        border: `2px solid ${u.role === 'admin' ? 'var(--purple-light)' : u.role === 'community_admin' ? 'var(--cyan-accent)' : 'var(--text-secondary)'}40`,
                      }}>
                        {u.name?.charAt(0).toUpperCase()}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{
                          fontWeight: 700,
                          fontSize: '1rem',
                          marginBottom: '4px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'space-between',
                          flexWrap: 'wrap',
                          gap: '8px',
                        }}>
                          {u.name}
                          <span className={`badge badge-${u.role}`} style={{ fontSize: '0.7rem' }}>
                            {u.role === 'community_admin' ? 'Comm. Admin' : u.role}
                          </span>
                        </div>
                        <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>{u.email}</div>
                      </div>
                    </div>

                    {/* User Details */}
                    <div style={{
                      fontSize: '0.75rem',
                      marginBottom: '16px',
                      padding: '12px',
                      background: 'rgba(0, 0, 0, 0.2)',
                      borderRadius: '12px',
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                        <span style={{ color: 'var(--text-muted)' }}>IT Number</span>
                        <span style={{ fontFamily: 'var(--font-mono)', color: 'var(--cyan-accent)' }}>{u.itNumber || '—'}</span>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                        <span style={{ color: 'var(--text-muted)' }}>Community</span>
                        <span style={{ color: 'var(--text-secondary)' }}>{u.managedCommunity?.name || '—'}</span>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span style={{ color: 'var(--text-muted)' }}>Joined</span>
                        <span style={{ color: 'var(--text-secondary)' }}>{new Date(u.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                      </div>
                    </div>

                    {/* Status Badge */}
                    <div style={{ marginBottom: '16px' }}>
                      <span style={{
                        display: 'inline-flex',
                        alignItems: 'center',
                        gap: '4px',
                        padding: '4px 12px',
                        borderRadius: '20px',
                        fontSize: '0.7rem',
                        fontWeight: 500,
                        background: u.status === 'pending' ? 'rgba(255, 193, 7, 0.1)' : u.status === 'approved' ? 'rgba(0, 255, 0, 0.1)' : 'rgba(255, 0, 0, 0.1)',
                        color: u.status === 'pending' ? 'var(--warning)' : u.status === 'approved' ? 'var(--success)' : 'var(--error)',
                      }}>
                        {u.status === 'pending' ? '⏳' : u.status === 'approved' ? '✓' : '✗'} {u.status.toUpperCase()}
                      </span>
                    </div>

                    {/* Actions */}
                    <div style={{ display: 'flex', gap: '8px' }}>
                      {u.status === 'pending' && (
                        <>
                          <button
                            onClick={() => approveUser(u._id, u.name)}
                            style={{
                              flex: 1,
                              padding: '8px',
                              borderRadius: '10px',
                              background: 'rgba(0, 255, 0, 0.1)',
                              border: '1px solid rgba(0, 255, 0, 0.3)',
                              color: 'var(--success)',
                              cursor: 'pointer',
                              fontSize: '0.75rem',
                              fontWeight: 600,
                              transition: 'all 0.2s',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              gap: '4px',
                            }}
                            onMouseEnter={(e) => {
                              e.currentTarget.style.background = 'rgba(0, 255, 0, 0.2)';
                              e.currentTarget.style.transform = 'translateY(-1px)';
                            }}
                            onMouseLeave={(e) => {
                              e.currentTarget.style.background = 'rgba(0, 255, 0, 0.1)';
                              e.currentTarget.style.transform = 'translateY(0)';
                            }}
                          >
                            ✓ Approve
                          </button>
                          <button
                            onClick={() => rejectUser(u._id, u.name)}
                            style={{
                              flex: 1,
                              padding: '8px',
                              borderRadius: '10px',
                              background: 'rgba(255, 0, 0, 0.1)',
                              border: '1px solid rgba(255, 0, 0, 0.3)',
                              color: 'var(--error)',
                              cursor: 'pointer',
                              fontSize: '0.75rem',
                              fontWeight: 600,
                              transition: 'all 0.2s',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              gap: '4px',
                            }}
                            onMouseEnter={(e) => {
                              e.currentTarget.style.background = 'rgba(255, 0, 0, 0.2)';
                              e.currentTarget.style.transform = 'translateY(-1px)';
                            }}
                            onMouseLeave={(e) => {
                              e.currentTarget.style.background = 'rgba(255, 0, 0, 0.1)';
                              e.currentTarget.style.transform = 'translateY(0)';
                            }}
                          >
                            ✗ Reject
                          </button>
                        </>
                      )}
                      {u.role !== 'admin' && (
                        <button
                          onClick={() => deleteUser(u._id, u.name)}
                          style={{
                            padding: '8px',
                            borderRadius: '10px',
                            background: 'rgba(255, 0, 0, 0.05)',
                            border: '1px solid rgba(255, 0, 0, 0.2)',
                            color: 'var(--error)',
                            cursor: 'pointer',
                            fontSize: '0.75rem',
                            transition: 'all 0.2s',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '4px',
                            width: u.status === 'pending' ? 'auto' : '100%',
                          }}
                          onMouseEnter={(e) => {
                            e.currentTarget.style.background = 'rgba(255, 0, 0, 0.1)';
                            e.currentTarget.style.transform = 'translateY(-1px)';
                          }}
                          onMouseLeave={(e) => {
                            e.currentTarget.style.background = 'rgba(255, 0, 0, 0.05)';
                            e.currentTarget.style.transform = 'translateY(0)';
                          }}
                        >
                          🗑 Delete
                        </button>
                      )}
                      {u.status !== 'pending' && u.role === 'admin' && (
                        <div style={{
                          flex: 1,
                          padding: '8px',
                          borderRadius: '10px',
                          background: 'rgba(0, 255, 255, 0.05)',
                          border: '1px solid rgba(0, 255, 255, 0.2)',
                          textAlign: 'center',
                          fontSize: '0.7rem',
                          color: 'var(--text-muted)',
                        }}>
                          Admin Account
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Pagination */}
            {pages > 1 && (
              <div style={{
                display: 'flex',
                gap: '8px',
                justifyContent: 'center',
                alignItems: 'center',
                flexWrap: 'wrap',
                marginTop: '8px',
                padding: '16px',
              }}>
                <button
                  onClick={() => setFilters(prev => ({ ...prev, page: Math.max(1, prev.page - 1) }))}
                  disabled={filters.page === 1}
                  style={{
                    padding: '8px 14px',
                    borderRadius: '10px',
                    background: 'rgba(10, 18, 26, 0.6)',
                    border: '1px solid rgba(0, 255, 255, 0.2)',
                    color: filters.page === 1 ? 'var(--text-muted)' : 'var(--cyan-accent)',
                    cursor: filters.page === 1 ? 'not-allowed' : 'pointer',
                    transition: 'all 0.2s',
                  }}
                >
                  ← Previous
                </button>
                {Array.from({ length: Math.min(5, pages) }, (_, i) => {
                  let pageNum;
                  if (pages <= 5) {
                    pageNum = i + 1;
                  } else if (filters.page <= 3) {
                    pageNum = i + 1;
                  } else if (filters.page >= pages - 2) {
                    pageNum = pages - 4 + i;
                  } else {
                    pageNum = filters.page - 2 + i;
                  }
                  return (
                    <button
                      key={pageNum}
                      onClick={() => setFilters(prev => ({ ...prev, page: pageNum }))}
                      style={{
                        padding: '8px 14px',
                        borderRadius: '10px',
                        background: filters.page === pageNum ? 'rgba(0, 255, 255, 0.2)' : 'rgba(10, 18, 26, 0.6)',
                        border: `1px solid ${filters.page === pageNum ? 'var(--cyan-accent)' : 'rgba(0, 255, 255, 0.2)'}`,
                        color: filters.page === pageNum ? 'var(--cyan-accent)' : 'var(--text-secondary)',
                        cursor: 'pointer',
                        transition: 'all 0.2s',
                      }}
                    >
                      {pageNum}
                    </button>
                  );
                })}
                <button
                  onClick={() => setFilters(prev => ({ ...prev, page: Math.min(pages, prev.page + 1) }))}
                  disabled={filters.page === pages}
                  style={{
                    padding: '8px 14px',
                    borderRadius: '10px',
                    background: 'rgba(10, 18, 26, 0.6)',
                    border: '1px solid rgba(0, 255, 255, 0.2)',
                    color: filters.page === pages ? 'var(--text-muted)' : 'var(--cyan-accent)',
                    cursor: filters.page === pages ? 'not-allowed' : 'pointer',
                    transition: 'all 0.2s',
                  }}
                >
                  Next →
                </button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
